SELECT [Sales Line].[Document Type], [Sales Line].Type, [Sales Line].No_, [Sales Line].Quantity, [Sales Line].[Unit of Measure], [Sales Line].[Constant Variable Code], [Sales Line].[Assortment Code], [Sales Line].[No_ of Pairs], Salesperson_Purchaser.Name AS Salesperson, [Sales Line].[Delete Reason], [Sales Line].[Customer Price Group], [Sales Line].[Average Unit Price], [Sales Header].[Order Date], [Sales Header].[Salesperson Code], [Sales Line].[Constant Variable Code] AS ColorCode, [Sales Header].[Sell-to Customer No_], Val([Line Amount])-Val([Inv_ Discount Amount]) AS SalesValue, [Sales Line].[Quantity Shipped], [Sales Line].[Quantity Invoiced], [Sales Line].[Document No_], [Sales Line].[Line No_], [Sales Header].[Ship-to Name], [Sales Header].[Ship-to Name 2], [Sales Header].[Ship-to Address], [Sales Header].[Ship-to Address 2], [Sales Header].[Ship-to City], [Sales Header].[Ship-to Post Code], [Sales Header].[Ship-to County], [Sales Header].[Ship-to Country Code]
FROM (([Sales Line] INNER JOIN [Sales Header] ON ([Sales Line].[Document Type] = [Sales Header].[Document Type]) AND ([Sales Line].[Document No_] = [Sales Header].No_)) LEFT JOIN Salesperson_Purchaser ON [Sales Header].[Salesperson Code] = Salesperson_Purchaser.Code) INNER JOIN [Variable Code] ON ([Sales Line].[Constant Assortment Var_Grp_] = [Variable Code].[Variable Group]) AND ([Sales Line].[Constant Variable Code] = [Variable Code].[Variable Code])
WHERE ((([Sales Line].[Document Type])=1) AND (([Sales Line].Type)=20 Or ([Sales Line].Type)=19));

